const body = $('Webhook - Nhận tin nhắn KH').item.json['body'];

const customerId      = body['customer_id'] || '';
const sessionId       = body['session_id']  || ('session_' + Date.now());
const customerMessage = body['message']     || '';
const allProducts     = body['products']    || [];
const cartItems       = body['cart']        || [];
const purchaseHistory = body['purchase_history'] || [];

// Format catalog
const productCatalog = allProducts.map(function(p) {
  const priceNum     = Number(p['price'])      || 0;
  const salePriceNum = Number(p['sale_price']) || 0;
  const priceStr = (salePriceNum > 0 && salePriceNum < priceNum)
    ? salePriceNum.toLocaleString('vi-VN') + 'đ (giảm từ ' + priceNum.toLocaleString('vi-VN') + 'đ)'
    : priceNum.toLocaleString('vi-VN') + 'đ';
  const stockStatus = (p['stock'] > 0) ? ('Còn ' + p['stock']) : 'Hết hàng';
  return '[' + p['sku'] + '] ' + p['name'] + ' | ' + p['category'] + ' | ' + priceStr + ' | ' + stockStatus + '\n  Mô tả: ' + (p['description'] || '');
}).join('\n---\n');

// Format cart
const cartSummary = cartItems.length > 0
  ? cartItems.map(function(c) {
      return '- [' + c['sku'] + '] ' + c['name'] + ' × ' + c['quantity'] + ' = ' + (c['price'] * c['quantity']).toLocaleString('vi-VN') + 'đ';
    }).join('\n')
  : 'Giỏ hàng đang trống.';

// Format history
const historySummary = purchaseHistory.length > 0
  ? purchaseHistory.map(function(h) {
      return '- [' + h['sku'] + '] ' + h['name'] + ' (' + h['category'] + ') - đã mua ' + (h['times_bought'] || 1) + ' lần';
    }).join('\n')
  : 'Chưa có lịch sử mua hàng.';

const systemPrompt = `Bạn là chuyên gia tư vấn sản phẩm thông minh. Nhiệm vụ:
1. Tư vấn dựa CHÍNH XÁC trên catalog sản phẩm được cung cấp.
2. Gợi ý tối đa 3-5 sản phẩm dựa trên giỏ hàng và lịch sử mua.
3. Dùng tiếng Việt tự nhiên, thân thiện, ngắn gọn.
4. Khi mention sản phẩm LUÔN kèm mã [SKU].
5. Chỉ recommend sản phẩm còn hàng. KHÔNG bịa thêm thông tin.

Trả về JSON với format:
{
  "reply": "<câu trả lời thân thiện>",
  "recommendations": [
    { "sku": "<SKU>", "name": "<tên>", "reason": "<lý do ngắn>", "price": <số>, "category": "<danh mục>" }
  ],
  "intent": "<product_query|price_check|recommendation|complaint|other>"
}`;

const userPrompt = `=== TIN NHẮN KHÁCH HÀNG ===
Customer ID: ${customerId}
Nội dung: ${customerMessage}

=== GIỎ HÀNG HIỆN TẠI ===
${cartSummary}

=== LỊCH SỬ MUA HÀNG ===
${historySummary}

=== CATALOG SẢN PHẨM (${allProducts.length} sản phẩm) ===
${productCatalog}

Hãy tư vấn và gợi ý sản phẩm. Trả về đúng format JSON.`;

return [{
  json: {
    customer_id:      customerId,
    session_id:       sessionId,
    customer_message: customerMessage,
    system_prompt:    systemPrompt,
    user_prompt:      userPrompt,
    product_count:    allProducts.length
  }
}];

const novaResponse = $json;
const prev = $('Code - Build AI Prompt').item.json;

// Extract text from Nova response
let rawText = '';
let inputTokens  = 0;
let outputTokens = 0;
let finishReason = 'end_turn';

try {
  rawText      = novaResponse['output']['message']['content'][0]['text'];
  inputTokens  = (novaResponse['usage'] || {})['inputTokens']  || 0;
  outputTokens = (novaResponse['usage'] || {})['outputTokens'] || 0;
  finishReason = novaResponse['stopReason'] || 'end_turn';
} catch(e) {
  rawText = JSON.stringify(novaResponse);
}

// Parse JSON from AI reply
let parsed = null;
try {
  parsed = JSON.parse(rawText);
} catch(e1) {
  try {
    const match = rawText.match(/\{[\s\S]*\}/);
    if (match) parsed = JSON.parse(match[0]);
    else throw new Error('No JSON');
  } catch(e2) {
    parsed = {
      reply: rawText || 'Xin lỗi, tôi không thể xử lý yêu cầu. Vui lòng thử lại.',
      recommendations: [],
      intent: 'other'
    };
  }
}

// Safety / content filter block
if (finishReason === 'content_filtered') {
  parsed = {
    reply: 'Xin lỗi, tôi không thể trả lời câu hỏi này. Vui lòng liên hệ nhân viên hỗ trợ.',
    recommendations: [],
    intent: 'blocked'
  };
}

const recs = (parsed['recommendations'] || []).slice(0, 5).map(function(r) {
  return {
    sku:      r['sku']      || '',
    name:     r['name']     || '',
    reason:   r['reason']   || '',
    price:    r['price']    || 0,
    category: r['category'] || ''
  };
});

return [{
  json: {
    customer_id:      prev['customer_id'],
    session_id:       prev['session_id'],
    original_message: prev['customer_message'],
    reply:            parsed['reply'] || '',
    recommendations:  recs,
    intent:           parsed['intent'] || 'other',
    meta: {
      model:         'amazon.nova-lite-v1:0',
      input_tokens:  inputTokens,
      output_tokens: outputTokens,
      finish_reason: finishReason,
      timestamp:     new Date().toISOString()
    }
  }
}];
